// ═══════════════════════════════════════════════════════
// CLOCK — Real-time with timezone support
// ═══════════════════════════════════════════════════════

function ClockWidget({ config, compact }: { config: any; compact: boolean }) {
  if (config.theme === 'principals-office') return <PrincipalsOfficeClock config={config} compact={compact} />;
  if (config.theme === 'office-dashboard') return <OfficeDashboardClock config={config} compact={compact} />;
  if (config.theme === 'back-to-school') return <BackToSchoolClock config={config} />;
  if (config.theme === 'bus-loop') return <BusLoopClock config={config} />;
  if (config.theme === 'diner-chalkboard') return <DinerChalkboardClock config={config} />;
  if (config.theme === 'rainbow-animated') return <RainbowAnimatedClock config={config} />;
  if (config.theme === 'rainbow-ribbon') return <RainbowRibbonClock config={config} compact={compact} />;
  if (config.theme === 'field-day') return <FieldDayClock config={config} compact={compact} />;
  if (config.theme === 'bulletin-board') return <BulletinBoardClock config={config} compact={compact} />;
  if (config.theme === 'storybook') return <StorybookClock config={config} compact={compact} />;
  if (config.theme === 'scrapbook') return <ScrapbookClock config={config} compact={compact} />;
  if (config.theme === 'track-day') return <TrackDayClock config={config} compact={compact} />;
  if (config.theme === 'scorebug') return <ScorebugClock config={config} compact={compact} />;
  if (config.theme === 'jumbotron-pro') return <JumbotronProClock config={config} compact={compact} />;
  if (config.theme === 'locker-hallway') return <LockerHallwayClock config={config} compact={compact} />;
  if (config.theme === 'spirit-rally') return <SpiritRallyClock config={config} compact={compact} />;
  if (config.theme === 'stem-lab') return <StemLabClock config={config} compact={compact} />;
  if (config.theme === 'morning-news') return <MorningNewsClock config={config} compact={compact} />;
  if (config.theme === 'art-studio') return <ArtStudioClock config={config} compact={compact} />;
  if (config.theme === 'varsity-athletic') return <VarsityAthleticClock config={config} compact={compact} />;
  if (config.theme === 'senior-countdown') return <SeniorCountdownClock config={config} compact={compact} />;
  if (config.theme === 'news-studio-pro') return <NewsStudioProClock config={config} compact={compact} />;
  if (config.theme === 'campus-quad') return <CampusQuadClock config={config} compact={compact} />;
  if (config.theme === 'achievement-hall') return <AchievementHallClock config={config} compact={compact} />;
  if (config.theme === 'final-chance') return <FinalChanceClock config={config} />;
  if (config.theme === 'library-quiet') return <LibraryQuietClock config={config} />;
  if (config.theme === 'middle-school-hall') return <MSHallClock config={config} />;
  if (config.theme === 'sunshine-academy') return <SunshineAcademyClock config={config} compact={compact} />;
  // Theme router — render a themed variant if requested
  if (config.theme === 'sunny-meadow') return <SunnyMeadowClock config={config} compact={compact} />;

  const [now, setNow] = useState(new Date());
  useEffect(() => {
    const t = setInterval(() => setNow(new Date()), 1000);
    return () => clearInterval(t);
  }, []);

  const tz = config.timezone || undefined; // e.g. "America/Chicago"
  const is24 = config.format === '24h';

  // Use Intl to get timezone-aware values
  const fmt = (opts: Intl.DateTimeFormatOptions) =>
    new Intl.DateTimeFormat('en-US', { ...opts, timeZone: tz }).format(now);

  const rawHour = parseInt(fmt({ hour: 'numeric', hour12: false }), 10);
  const ampm = rawHour >= 12 ? 'PM' : 'AM';
  const hours = is24 ? rawHour : (rawHour % 12 || 12);
  const mins = fmt({ minute: '2-digit' }).padStart(2, '0');
  const secs = fmt({ second: '2-digit' }).padStart(2, '0');
  const dateStr = fmt({ weekday: 'long', month: 'long', day: 'numeric', year: 'numeric' });

  const color = config.color || '#1e293b';
  const bg = config.bgColor || 'transparent';

  // Show timezone abbreviation if explicitly set
  const tzLabel = tz ? fmt({ timeZoneName: 'short' }).split(', ').pop() : null;

  return (
    <div className="absolute inset-0 flex flex-col items-center justify-center overflow-hidden" style={{ backgroundColor: bg }}>
      <div className="flex items-baseline gap-[0.1em] tabular-nums" style={{ color }}>
        <span style={{ fontSize: compact ? '1.8em' : '3.5em', fontWeight: 800, letterSpacing: '-0.02em', lineHeight: 1 }}>
          {hours}:{mins}
        </span>
        <span style={{ fontSize: compact ? '0.7em' : '1.2em', fontWeight: 600, opacity: 0.4 }}>{secs}</span>
        {!is24 && <span style={{ fontSize: compact ? '0.6em' : '1em', fontWeight: 700, opacity: 0.5, marginLeft: '0.15em' }}>{ampm}</span>}
      </div>
      {!compact && (
        <div style={{ fontSize: '0.65em', fontWeight: 500, opacity: 0.45, marginTop: '0.3em', color, letterSpacing: '0.05em' }}>
          {dateStr}
        </div>
      )}
      {tzLabel && !compact && (
        <div style={{ fontSize: '0.45em', fontWeight: 600, opacity: 0.35, marginTop: '0.15em', color, letterSpacing: '0.08em', textTransform: 'uppercase' as const }}>
          {tzLabel}
        </div>
      )}
    </div>
  );
}

